class Order {
  String streetAddress;
  String city;
  String zipCode;
}

class Customer {
  String streetAddress;
  String city;
  String zipCode;
}

// After (refactored)
class Address {
  String streetAddress;
  String city;
  String zipCode;
}

class Order { Address address; }
class Customer { Address address; }

